  ('disabled-7fec267e-moex-00065', 'disabled-7fec267e', 'disabled-7fec267e-moex-114-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '我國中國鋼鐵公司的「民營化」，主要係透過下列何種方式完成組織轉型的 目標？', '["BOT模式", "撤資出售", "發行抵用券", "行政法人化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "35e3be3d56e2", "answer_pdf_sha1": "e1ffdf6b6fe7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00066', 'disabled-7fec267e', 'disabled-7fec267e-moex-114-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'essay', 'A大學透過校務會議，訂定「A大學汽、機車入校管理規則」（下稱
汽機車管理規則），其中明文規定，機車沒有特殊許可，禁止進入校
園，違者處罰鍰新臺幣（下同）100 元。某甲為 A大學學生，未經特
殊許可騎車進入校園 10 次，被校警依汽機車管理規則共處 1,000 元
罰鍰。某甲後來修滿學分，依學位授予法規定，具有取得學士學位資
格。但在辦理離校手續時，某甲質疑學校無權訂定汽機車管理規則，
並拒絕繳納該罰鍰，A 大學遂拒絕給予畢業證書。請問： A 大學
是否具有訂定僅適用於校內的汽機車管理規則？ A 大學以某甲未
繳清罰鍰而拒絕發給畢業證書，是否合法？某甲如欲提起訴訟，請
求交付畢業證書，應提起何種行政訴訟類型？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00067', 'disabled-7fec267e', 'disabled-7fec267e-moex-114-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'essay', '行政程序法第 117 條規定：「違法行政處分於法定救濟期間經過後，
原處分機關得依職權為全部或一部之撤銷；其上級機關，亦得為之。
但有下列各款情形之一者，不得撤銷︰……。」請問：本條明文規
定，原處分機關不得撤銷違法行政處分之情形有那些？針對該行政
處分，如果當事人對之曾提起訴願及行政訴訟，最後被最高行政法院
駁回確定，但原處分機關後來發現，原行政處分確實有違法之處，是
否仍可依職權自行撤銷？其法理依據為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00068', 'disabled-7fec267e', 'disabled-7fec267e-moex-114-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於法律保留原則之敘述，下列何者錯誤？', '["大學生退學處分事項，不得由大學自訂章則加以規範，而必須以法律定之", "人民依法律納稅為法律保留原則之展現", "違反行政法上義務之處罰，以行為時之法律或自治條例明文規定者為限", "公務人員退休年資之計算，屬法律保留之事項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00069', 'disabled-7fec267e', 'disabled-7fec267e-moex-114-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '藥害救濟法第 13 條規定：「有下列各款情事之一者，不得申請藥害救濟 ：……九、常見且可預期之藥物不良反應。」關於本條規定，依司法院大 法官解釋意旨，下列敘述何者錯誤？', '["立法者以不確定法律概念規範藥害救濟申請之構成要件，有成立判斷餘 地之可能", "「常見」、「可預期」之意義，依一般人民日常生活與語言經驗，已屬 難以理解", "針對「藥物不良反應」，可透過醫師告知與藥袋標示或藥物仿單而具備 可預見性", "藥害救濟之審議於實務上累積諸多案例，因此，最終可由司法審查來加 以確認"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL)
